import{_ as d,C as p,o as r,c,a3 as o,b as i,w as a,a as l,E as s,a4 as n}from"./chunks/framework.C49Ar5GK.js";const R=JSON.parse('{"title":"Worker 与资源编排：谁占 GPU，谁只是控制器","description":"区分算法角色、Ray actor、WorkerGroup、ResourcePool 和模型并行引擎，理解单机多机放置与共置取舍","frontmatter":{"title":"Worker 与资源编排：谁占 GPU，谁只是控制器","description":"区分算法角色、Ray actor、WorkerGroup、ResourcePool 和模型并行引擎，理解单机多机放置与共置取舍","lesson":{"stage":"04 · 源码","order":18,"time":"50–70 分钟","level":"分布式入门","question":"actor、rollout、critic、Ray actor、rank 和 GPU 到底怎样对应？"}},"headers":[],"relativePath":"internals/workers.md","filePath":"internals/workers.md","lastUpdated":null}'),h={name:"internals/workers.md"};function k(u,e,_,A,E,g){const t=p("Mermaid");return r(),c("div",null,[e[3]||(e[3]=o('<h1 id="worker-与资源编排-谁占-gpu-谁只是控制器" tabindex="-1">Worker 与资源编排：谁占 GPU，谁只是控制器 <a class="header-anchor" href="#worker-与资源编排-谁占-gpu-谁只是控制器" aria-label="Permalink to &quot;Worker 与资源编排：谁占 GPU，谁只是控制器&quot;">​</a></h1><p>veRL 用 Ray 把逻辑角色放进资源池，再由 WorkerGroup 统一分发调用。读这部分时分开三个概念：角色说明职责，资源池说明放置，模型引擎说明如何并行计算。</p><h2 id="先用人话-岗位、工位与工作方式" tabindex="-1">先用人话：岗位、工位与工作方式 <a class="header-anchor" href="#先用人话-岗位、工位与工作方式" aria-label="Permalink to &quot;先用人话：岗位、工位与工作方式&quot;">​</a></h2><ul><li>role 是岗位：actor 负责更新策略，rollout 负责生成；</li><li>ResourcePool 是工位分配：哪些节点/GPU 可被这个岗位占用；</li><li>WorkerGroup 是同一岗位的多 rank 组织与调用入口；</li><li>FSDP/Megatron/VeOmni 等 model engine 是岗位内部怎样拆分计算；</li><li>Ray actor 是运行时进程抽象，不等于 RL 的 actor policy。</li></ul><p>把这五层混起来，就会出现“我有 8 张 GPU，为什么 actor 还 pending”这类无法回答的问题。</p><h2 id="角色关系" tabindex="-1">角色关系 <a class="header-anchor" href="#角色关系" aria-label="Permalink to &quot;角色关系&quot;">​</a></h2>',6)),(r(),i(n,null,{default:a(()=>[s(t,{id:"mermaid-42",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20D%5BTaskRunner%20%2F%20PPOTrainer%3Cbr%2F%3E%E5%8D%95%E6%8E%A7%E5%88%B6%E5%99%A8%5D%0A%20%20%20%20RPM%5BResourcePoolManager%5D%0A%20%20%20%20D%20--%3E%20RPM%0A%20%20%20%20RPM%20--%3E%20AR%5BActorRolloutRef%20%2F%20ActorRollout%5D%0A%20%20%20%20RPM%20--%3E%20CR%5BCritic%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20RPM%20--%3E%20RR%5BRewardModel%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20RPM%20--%3E%20TT%5BTeacherModel%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20AR%20--%3E%20WG1%5BRayWorkerGroup%5D%0A%20%20%20%20CR%20--%3E%20WG2%5BRayWorkerGroup%5D%0A%20%20%20%20AR%20--%3E%20LS%5BLLM%20Server%20replicas%5D%0A%20%20%20%20RR%20--%3E%20RLM%5BRewardLoop%20workers%20%2F%20server%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<p>同一逻辑 role 可以根据 FSDP、Megatron、VeOmni 等 <code>model_engine</code> 选择不同 worker class。反过来，多个 role 也可能共置在一个 Ray actor/资源池中，以便共享 GPU，但它们的生命周期方法仍不同。</p><h2 id="核心角色" tabindex="-1">核心角色 <a class="header-anchor" href="#核心角色" aria-label="Permalink to &quot;核心角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>主要工作</th><th>何时可省略</th></tr></thead><tbody><tr><td>Actor</td><td>重算 log-prob、执行 policy loss、更新参数</td><td>不能省略</td></tr><tr><td>Rollout</td><td>通过 LLM server 生成 trajectory</td><td>不能省略，但可与 actor 共置</td></tr><tr><td>Reference</td><td>为 KL 提供冻结概率</td><td>没有 reward KL/actor KL 时可不启用</td></tr><tr><td>Critic</td><td>预测 value、训练 value loss</td><td>GRPO/RLOO 等无 critic 配方可省略</td></tr><tr><td>RewardModel</td><td>模型式打分</td><td>纯规则奖励可省略独立 RM</td></tr><tr><td>Teacher</td><td>on-policy distillation logits/信号</td><td>非蒸馏实验省略</td></tr></tbody></table><p><code>need_reference_policy()</code> 与 <code>need_critic()</code> 才是最终角色判断入口，不要只看某个孤立的 <code>enable</code> 字段。</p><h2 id="resourcepool-与-workergroup" tabindex="-1">ResourcePool 与 WorkerGroup <a class="header-anchor" href="#resourcepool-与-workergroup" aria-label="Permalink to &quot;ResourcePool 与 WorkerGroup&quot;">​</a></h2>',5)),(r(),i(n,null,{default:a(()=>[s(t,{id:"mermaid-138",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20CFG%5Bnnodes%20%C3%97%20n_gpus_per_node%5D%20--%3E%20POOL%5BRayResourcePool%5D%0A%20%20%20%20POOL%20--%3E%20P0%5Bnode0%3A%20GPU%200..k%5D%0A%20%20%20%20POOL%20--%3E%20P1%5Bnode1%3A%20GPU%200..k%5D%0A%20%20%20%20POOL%20--%3E%20WG%5BRayWorkerGroup%5D%0A%20%20%20%20WG%20--%3E%20R0%5Brank%200%5D%0A%20%20%20%20WG%20--%3E%20R1%5Brank%201%5D%0A%20%20%20%20WG%20--%3E%20RN%5Brank%20N-1%5D%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[l(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=o('<p>ResourcePoolManager 建立角色到 pool 的映射；<code>create_colocated_worker_cls</code> 可以把同一 pool 中的多个 worker class 包装成共置 actor；<code>RayWorkerGroup.spawn()</code> 再建立各 rank。调用 <code>compute_log_prob</code>、<code>update_actor</code> 等方法时，dispatch 层会按 DP mapping 切分 <code>KVBatchMeta</code>，worker 通过 TQ 读取字段。</p><p>因此 batch 约束至少涉及：</p><ul><li>轨迹条数能否被 data-parallel size 合理切分；</li><li>actor/critic 的 global mini-batch 与 <code>rollout.n</code>；</li><li>sequence-length balance 后每个 rank 的 token workload；</li><li>tensor/pipeline/expert parallel 对单副本 GPU 数的要求。</li></ul><h2 id="训练引擎与推理引擎不是同一个东西" tabindex="-1">训练引擎与推理引擎不是同一个东西 <a class="header-anchor" href="#训练引擎与推理引擎不是同一个东西" aria-label="Permalink to &quot;训练引擎与推理引擎不是同一个东西&quot;">​</a></h2><p>Actor WorkerGroup 持有可反向传播的训练模型；LLMServerManager 建立面向生成的 replicas。CheckpointEngineManager 连接二者：</p>',5)),(r(),i(n,null,{default:a(()=>[s(t,{id:"mermaid-173",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20A%20as%20Actor%20WorkerGroup%0A%20%20%20%20participant%20C%20as%20CheckpointEngineManager%0A%20%20%20%20participant%20L%20as%20LLM%20Server%20replica%0A%20%20%20%20A-%3E%3EA%3A%20optimizer%20step%0A%20%20%20%20C-%3E%3EA%3A%20%E8%AF%BB%E5%8F%96%2F%E5%AF%BC%E5%87%BA%E6%96%B0%E6%9D%83%E9%87%8D%0A%20%20%20%20C-%3E%3EL%3A%20update_weights(version)%0A%20%20%20%20L--%3E%3EC%3A%20replica%20ready%0A%20%20%20%20L-%3E%3EL%3A%20rollout%20with%20new%20version%0A"})]),fallback:a(()=>[...e[2]||(e[2]=[l(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=o(`<p>在共置模式，sleep/wake 还用于让训练和 rollout 分时使用显存。观察到 rollout server 暂停不一定是死锁；先确认 trainer 是否正处于训练/同步阶段以及生命周期日志是否前进。</p><h2 id="单机与多机的实际边界" tabindex="-1">单机与多机的实际边界 <a class="header-anchor" href="#单机与多机的实际边界" aria-label="Permalink to &quot;单机与多机的实际边界&quot;">​</a></h2><p>Ray 负责调度，但不会自动让所有路径和网络接口正确：</p><ul><li>模型、数据、checkpoint 与输出目录必须在对应 worker 节点可访问；</li><li>每节点对外通信 IP 要正确，不能让 collective 选到 loopback；</li><li>rollout server 的 host IP 通常是节点局部值，不能一份固定环境变量复制到所有节点；</li><li>NCCL/Gloo/设备可见性环境应在 Ray 节点/actor 启动前生效；</li><li><code>/tmp</code>、Ray session、模型 cache 与 TQ storage 要有足够容量。</li></ul><h2 id="资源问题的最小证据集" tabindex="-1">资源问题的最小证据集 <a class="header-anchor" href="#资源问题的最小证据集" aria-label="Permalink to &quot;资源问题的最小证据集&quot;">​</a></h2><p>遇到 pending actor、OOM 或 collective timeout 时，保存：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ray</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # Ascend 环境换成对应工具</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;import ray, verl; print(ray.__version__, verl.__file__)&#39;</span></span></code></pre></div><p>再记录 resolved config 中的 nodes/GPUs、各并行 size、placement/resource pool、模型 dtype、max prompt/response length 和 memory utilization。只有“8 张卡”不足以复现资源拓扑。</p><h2 id="通关检查" tabindex="-1">通关检查 <a class="header-anchor" href="#通关检查" aria-label="Permalink to &quot;通关检查&quot;">​</a></h2><p>选择你的 resolved config，画一张“role → WorkerGroup/rank → node/GPU → engine parallelism”表。再分别说明 reference 与 critic 为什么存在/省略、rollout server 与训练 actor 是否共置、一次权重同步跨过哪些进程边界。</p><p>源码主线到此闭环。下一步进入<a href="/losh_has_blog/verl-learning/customization/extension-map">扩展点地图</a>，把理解变成安全改动。</p>`,11))])}const m=d(h,[["render",k]]);export{R as __pageData,m as default};
